using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; } = 3;
}

namespace TicketClassifier.Models;

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<ModelTrainingService> _logger;

    // Category labels in the order ML.NET assigns them
    public static readonly string[] CategoryLabels = ["Billing", "General", "Technical"];

    public ModelTrainingService(IConfiguration configuration, ILogger<ModelTrainingService> logger)
    {
        _dataPath = configuration.GetValue<string>("MLModel:DataPath")
            ?? Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = configuration.GetValue<string>("MLModel:ModelPath")
            ?? Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        _logger = logger;
    }

    public string ModelPath => _modelPath;

    public void TrainAndEvaluate()
    {
        var mlContext = new MLContext(seed: 42);

        // Load data
        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Split for evaluation
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Build pipeline: featurize text + numeric, then classify
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Train
        _logger.LogInformation("Training model with {Path}...", _dataPath);
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        _logger.LogInformation("===== Model Evaluation Metrics =====");
        _logger.LogInformation("Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);
        _logger.LogInformation("Per-class:");
        for (int i = 0; i < metrics.PerClassLogLoss.Count; i++)
        {
            _logger.LogInformation("  Class {Index}: LogLoss={LogLoss:F4}",
                i, metrics.PerClassLogLoss[i]);
        }
        _logger.LogInformation("Confusion Matrix:\n{Matrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        // Save model
        Directory.CreateDirectory(Path.GetDirectoryName(_modelPath)!);
        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;

    public TicketController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < ModelTrainingService.CategoryLabels.Length; i++)
        {
            confidence[ModelTrainingService.CategoryLabels[i]] = prediction.Score[i];
        }

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }
}

