using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

var app = builder.Build();

// Train model at startup and register prediction pool
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
trainer.TrainAndEvaluate();

// Re-build with prediction pool now that the model file exists
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild app with the prediction pool registered
var fullBuilder = WebApplication.CreateBuilder(args);
fullBuilder.Services.AddControllers();
fullBuilder.Services.AddSingleton<ModelTrainingService>();
fullBuilder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

var fullApp = fullBuilder.Build();
fullApp.MapControllers();
fullApp.Run();

